log_file.close()

temperature_presets = {}

for line in log_data:
    match = re.search(r'\[(\d{2}:\d{2}:\d{2})\]', line)
    if match:
        time = datetime.datetime.strptime(match.group(1), '%H:%M:%S')
        if time.hour < 6:
            temperature = 'cool'
        elif time.hour < 12:
            temperature = 'warm'
        else:
            temperature = 'comfortable'
        if time in temperature_presets:
            temperature_presets[time].append(temperature)
        else:
            temperature_presets[time] = [temperature]

print(temperature_presets)
